  // =========================================================================
  test("with_in_global_scope") {
    assertCompresses(
      input = """var o = 42;
        with(o) {
            var foo = 'something'
        }
        doSomething(o)""".stripMargin.trim,
      expected = """var o=42;
        with(o)
            var foo = "something";
        doSomething(o)""".stripMargin.trim,
      options = AllOff.copy(
        unused = true
      )
    )
  }

